25	function AttemptRow({ attempt }: { attempt: TaskAttempt }) {
26	  const icon =
27	    attempt.outcome === "completed" ? (
28	      <CheckCircle2 className="size-4 text-success" aria-hidden />
29	    ) : attempt.outcome === "failed" ? (
30	      <XCircle className="size-4 text-destructive" aria-hidden />
31	    ) : (
32	      <Loader2 className="size-4 animate-spin text-muted-foreground" aria-hidden />
33	    );
34	  return (
35	    <li
36	      data-testid="task-attempt-row"
37	      data-outcome={attempt.outcome}
38	      className="flex gap-3"
39	    >
40	      <div className="mt-1 shrink-0">{icon}</div>
41	      <div className="min-w-0 flex-1 space-y-0.5">
42	        <div className="flex flex-wrap items-baseline gap-x-3 text-sm">
43	          <span className="font-medium">Attempt #{attempt.index}</span>
44	          <span
45	            className="text-xs text-muted-foreground"
46	            title={formatDateTime(attempt.started_at)}
47	          >
48	            started {formatRelativeTime(attempt.started_at)}
49	          </span>
50	          {attempt.ended_at ? (
51	            <span className="text-xs text-muted-foreground">
52	              · {formatDuration(attempt.duration_ms)}
53	            </span>
54	          ) : (
55	            <span className="text-xs text-muted-foreground">· still running</span>
56	          )}
57	          <span className="text-xs text-muted-foreground">· {attempt.actor}</span>
58	        </div>
59	        {attempt.detail ? (
60	          <p className="text-xs text-muted-foreground break-words">
61	            {attempt.detail}
62	          </p>
63	        ) : null}
64	      </div>
65	    </li>
66	  );
67	}
68	
69	export function TaskAttemptsTimeline({
70	  taskId,
71	  initialEvents,
72	  isActive,
73	}: TaskAttemptsTimelineProps) {
74	  const api = useApi();
75	  const { data: events = initialEvents } = useQuery({
76	    queryKey: ["task-events", taskId],
77	    queryFn: () => api.fetch<AuditEvent[]>(`/api/tasks/${taskId}/logs?limit=500`),
78	    initialData: initialEvents,
79	    refetchInterval: isActive ? 5_000 : false,
80	  });
81	
82	  const attempts = deriveAttempts(events);
83	
84	  return (
85	    <Card data-testid="task-attempts-timeline">
86	      <CardHeader>
87	        <CardTitle className="text-lg">Attempts</CardTitle>
88	        <CardDescription>
89	          {attempts.length === 0
90	            ? "This task has not been dispatched yet."
91	            : `${attempts.length} attempt${attempts.length === 1 ? "" : "s"} so far.`}
92	        </CardDescription>
93	      </CardHeader>
94	      <CardContent>
95	        {attempts.length === 0 ? (
96	          <p
97	            data-testid="task-attempts-empty"
98	            className="text-sm text-muted-foreground"
99	          >
100	            Attempts will appear once an agent starts running the task.
101	          </p>
102	        ) : (
103	          <ol className="space-y-3">
104	            {[...attempts].reverse().map((attempt) => (
105	              <AttemptRow key={attempt.index} attempt={attempt} />
106	            ))}
107	          </ol>
108	        )}
109	      </CardContent>
110	    </Card>
111	  );
112	}
